tape( 'the function returns `+infinity` for very large `x`', opts, function test( t ) {
	t.strictEqual( exp10f( 100.0 ), PINF, 'equals +infinity' );
	t.strictEqual( exp10f( 200.0 ), PINF, 'equals +infinity' );
	t.strictEqual( exp10f( 300.0 ), PINF, 'equals +infinity' );
	t.end();
});

tape( 'the function returns `0.0` for negative large `x`', opts, function test( t ) {
	t.strictEqual( exp10f( -100.0 ), 0.0, 'equals 0' );
	t.strictEqual( exp10f( -200.0 ), 0.0, 'equals 0' );
	t.strictEqual( exp10f( -300.0 ), 0.0, 'equals 0' );
	t.end();
});

tape( 'the function returns `0.0` if provided `-infinity`', opts, function test( t ) {
	var val = exp10f( NINF );
	t.strictEqual( isPositiveZerof( val ), true, 'returns expected value' );
	t.end();
});

tape( 'the function returns `+infinity` if provided `+infinity`', opts, function test( t ) {
	t.strictEqual( exp10f( PINF ), PINF, 'equals +infinity' );
	t.end();
});

tape( 'the function returns `1` if provided `+-0`', opts, function test( t ) {
	var val;

	val = exp10f( -0.0 );
	t.strictEqual( val, 1.0, 'returns expected value' );

	val = exp10f( +0.0 );
	t.strictEqual( val, 1.0, 'returns expected value' );

	t.end();
});

tape( 'the function returns `NaN` if provided `NaN`', opts, function test( t ) {
	var val = exp10f( NaN );
	t.strictEqual( isnanf( val ), true, 'equals NaN' );
	t.end();
});
